const abuseData = $fromAI("abuseData", "Abuse case data for policy compliance verification", "json");
const policyRules = $fromAI("policyRules", "Organizational policy rules for enforcement", "json", {"autoSuspendThreshold": 3, "autoBanThreshold": 5, "warningBeforeSuspend": true});

try {
  const data = typeof abuseData === "string" ? JSON.parse(abuseData) : abuseData;
  const rules = typeof policyRules === "string" ? JSON.parse(policyRules) : policyRules;

  // Policy compliance checks
  const checks = {
    withinAutoSuspendThreshold: (data.violationCount || 0) < (rules.autoSuspendThreshold || 3),
    withinAutoBanThreshold: (data.violationCount || 0) < (rules.autoBanThreshold || 5),
    warningIssued: data.previousWarnings && data.previousWarnings.length > 0,
    requiresWarningFirst: rules.warningBeforeSuspend && !data.previousWarnings,
    severityCompliance: data.severityLevel !== "CRITICAL" || data.violationCount >= 1,
    noActiveAppeal: !data.activeAppeal || data.activeAppeal === false
  };

  const allChecksPassed = Object.values(checks).every(check => check === true);
  const failedChecks = Object.keys(checks).filter(key => checks[key] === false);

  // Determine recommended action based on policy
  let recommendedAction = "monitor";
  if (data.violationCount >= rules.autoBanThreshold) {
    recommendedAction = "ban";
  } else if (data.violationCount >= rules.autoSuspendThreshold) {
    recommendedAction = "suspend";
  } else if (data.severityLevel === "CRITICAL") {
    recommendedAction = "escalate";
  } else if (!data.previousWarnings || data.previousWarnings.length === 0) {
    recommendedAction = "warn";
  }

  const result = {
    complianceStatus: allChecksPassed ? "COMPLIANT" : "NON_COMPLIANT",
    checks: checks,
    failedChecks: failedChecks,
    policyViolations: failedChecks.map(check => `Failed: ${check}`),
    recommendedAction: recommendedAction,
    requiresHumanReview: !allChecksPassed || data.severityLevel === "CRITICAL",
    verificationDate: new Date().toISOString()
  };

  return JSON.stringify(result, null, 2);

} catch (error) {
  return JSON.stringify({
    complianceStatus: "ERROR",
    error: "Policy compliance check failed",
    message: error.message
  });
}

const governanceOutput = $input.first().json;
const behaviorSignal = $("Behavior Signal Agent").first().json;
const config = $("Workflow Configuration").first().json;

// Prepare comprehensive enforcement data
const enforcementData = {
  // Original signal data
  userId: behaviorSignal.userId,
  signalType: behaviorSignal.signalType,
  actionType: behaviorSignal.actionType,

  // Governance decision
  enforcementAction: governanceOutput.enforcementAction,
  actionDuration: governanceOutput.actionDuration,
  priority: governanceOutput.priority,

  // Risk assessment
  initialRiskScore: behaviorSignal.riskScore,
  refinedRiskScore: governanceOutput.refinedRiskScore,
  severityLevel: behaviorSignal.severityLevel,

  // Investigation and compliance
  investigationFindings: governanceOutput.investigationFindings,
  policyViolations: governanceOutput.policyViolations,
  coordinatedActions: governanceOutput.coordinatedActions,

  // Decision reasoning
  reasoning: governanceOutput.reasoning,
  requiresHumanReview: governanceOutput.requiresHumanReview,
  escalationReason: governanceOutput.escalationReason,

  // Metadata
  timestamp: new Date().toISOString(),
  workflowId: $workflow.id,
  executionId: $execution.id
};

return [{ json: enforcementData }];

